VALUES
  ('dietitian-moex-10454', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '台灣地區1979-1980年國民營養調查所使用之飲食調查方法主要之缺點為： 無法評量個人飲食攝取量   個別差異太大 容易高估營養素之攝取    食物回憶困難', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10455', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '所謂半定量飲食頻率問卷乃指該飲食頻率問卷之各個食物項目： 不計算其攝取量    給予一個固定的標準攝取量 紀錄每個人各類食物攝取份量  分別給予大、中、小三種份量選擇', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10456', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署於民國九十二年新修訂之「國人膳食營養素參考攝取量」中對維生素B 之建議量較前一版低之 1 原因為： 熱量之建議量降低    人體對維生素B 之需要量降低 1 國人之維生素B 攝取量沒有缺乏之虞  台灣地區生產之食物維生素B 含量豐富', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10457', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '1', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10458', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是我國九十二年新修訂之「國人膳食營養素參考攝取量」對鈣的建議量採用足夠攝取量（Adequate Intake, AI），而非建議攝取量（Recommended Dietary Allowance, RDA）的主要理由： 臨床上尚未有明確可靠、可反應鈣質營養狀態之生化指標 缺乏縱式研究數據，無法判斷鈣攝取量對骨骼與其他生理機能之長期影響或相關性 缺乏實驗值與觀察值間之相關性 缺乏國人鈣質攝取量之相關數據', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10459', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依台灣地區近年來營養調查結果，總缺鐵率最高的族群為？ 成年男性及一般青少年    成年女性及4-6歲幼兒 65歲以上男性及30-64歲女性  一般成年男性及65歲以上女性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10460', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師面質完個案後，發現個案在回答問題時，座位後移，此種情形可能代表該個案的不安感增加。此為 非口語行為（non-verbal behavior）中的何種行為？ 次語言行為（paralinguistics）  空間行為（proxemics） 動作學（kinesics）    人體力學', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10461', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某位營養師在進行一項營養諮詢時，詢問一位患者是否計畫於一個月內在飲食中增加蔬果的攝取，結果該 患者回答：「我可以考慮看看，不太一定」。請問此種反應，代表該患者處於營養教育理論中之「改變階 段模式」（Stages of change model）之那一個階段？ 行動期（action）    準備期（preparation） 思考期（contemplation）   思考前期（precontemplation）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10462', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當一位糖尿病患者相信他自己有降低飲食中脂肪攝取量的能力時，此種能力稱為： 自我效能（self-efficacy）   行為能力（behavior capacity） 增強（reinforcement）    期望（expectation）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10463', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '自1993年開始我國國民營養健康變遷調查用來評估國人營養攝取與飲食行為的方法包括那些？ 單獨使用24小時飲食回憶  飲食紀錄及飲食歷史 24小時飲食回憶及飲食頻率問卷  24小時飲食回憶及飲食紀錄', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
